        errors.append(f'External ref at {path}: {ref}')
        continue
    parts = ref[2:].split('/')
    node = spec
    for part in parts:
        if isinstance(node, dict) and part in node:
            node = node[part]
        else:
            errors.append(f'Broken ref at {path}: {ref} (missing {part})')
            break

if errors:
    for e in errors:
        print(f'ERROR: {e}')
    sys.exit(1)
else:
    print(f'OK: All {len(refs)} \$ref targets resolve successfully')
    print(f'Paths: {len(spec.get(\"paths\", {}))}')
